const now = Date.now();
const out = [];
for (const item of $input.all()) {
  const g = item.json;
  const enabled = g.enabled === true || g.enabled === 'true' || g.enabled === 1;
  if (!enabled) continue;
  const mins = Number(g.interval_minutes) || 15;
  const last = g.last_run_at ? new Date(g.last_run_at).getTime() : 0;
  if (!last || (now - last) >= mins * 60 * 1000) {
    out.push({ json: g });
  }
}
return out.length ? out : [{ json: { _skip: true } }];

function parseJson(val, fallback) {
  if (val == null || val === '') return fallback;
  if (typeof val === 'object') return val;
  try { return JSON.parse(val); } catch { return fallback; }
}

const serpTargets = $('Get SERP Targets').all().map(i => i.json);
const pdpTargets = $('Get PDP Targets').all().map(i => i.json);
const selectorRows = $('Get Selector Profiles').all().map(i => i.json);
const browserRows = $('Get Browser Profiles').all().map(i => i.json);
const dueGroups = $('Filter Due Groups').all().map(i => i.json).filter(g => !g._skip);

const selectorByKey = Object.fromEntries(selectorRows.map(s => [s.profile_key, s]));
const browserByKey = Object.fromEntries(browserRows.map(b => [b.profile_key, b]));

const jobs = [];
for (const group of dueGroups) {
  const selKey = group.selector_profile_key || 'amazon-us-default';
  const brKey = group.browser_profile_key || 'fast';
  const selRow = selectorByKey[selKey] || selectorRows[0];
  const brRow = browserByKey[brKey] || browserByKey.fast;
  if (!selRow || !brRow) continue;

  const selectors = parseJson(selRow.selectors_json, parseJson(selRow.selectors, {}));
  const browser = {
    profile: brRow.profile_key || 'fast',
    block_heavy: brRow.block_heavy !== false && brRow.block_heavy !== 'false',
    headless: group.headless !== false && group.headless !== 'false',
    channel: brRow.channel || 'chrome',
    goto_timeout_ms: Number(brRow.goto_timeout_ms) || 12000,
    ready_wait_ms: Number(brRow.ready_wait_ms) || 8000,
    max_goto_retries: Number(brRow.max_goto_retries) || 1,
    wait_until: brRow.wait_until || 'commit',
  };

  const kind = group.kind;
  const targets = kind === 'pdp'
    ? pdpTargets.filter(t => t.group_key === group.group_key)
    : serpTargets.filter(t => t.group_key === group.group_key);

  for (const target of targets) {
    const scrape = kind === 'pdp'
      ? {
          asins: [String(target.asin || '').toUpperCase()],
          max_concurrent: Number(group.max_concurrent) || 2,
        }
      : {
          search_url: target.search_url,
          scrape_mode: target.scrape_mode || 'newest_front',
          max_pages: Number(target.max_pages) || 1,
        };

    jobs.push({
      json: {
        group_key: group.group_key,
        kind,
        browser_profile: browser.profile,
        attempt: 1,
        trigger: 'scheduled',
        payload: { browser, selectors, scrape },
      },
    });
  }
}

return jobs.length ? jobs : [{ json: { _skip: true } }];

const seen = new Set();
const out = [];
for (const item of $('Build Jobs').all()) {
  const gk = item.json.group_key;
  if (!gk || item.json._skip || seen.has(gk)) continue;
  seen.add(gk);
  out.push({ json: { group_key: gk, last_run_at: new Date().toISOString() } });
}
return out;
